/* global console, process */
/*
 * aeon-hexon-braid — a signal evolving from noise to ABSOLUTE RESOLUTION.
 *
 * A model for how information flows: start at maximum entropy (broadband noise),
 * sweep the spectral-color ladder (brown -> pink -> white -> blue -> violet), woven
 * as a 6-strand HEXON braid (B6), and run it through a fractional (Hurst) regime
 * that contracts the spectrum toward a single coherent mode. Spectral entropy falls
 * to ~0 — the signal "resolves". That fully-resolved, single-mode state is gnosis's
 * geodesicLength:0 teleport target: absolute resolution.
 *
 *   color   beta(PSD~1/f^b)   Hurst H=(b+1)/2   character
 *   brown   +2                1.5  (over-persistent / Wiener-integrated)
 *   pink    +1                1.0  (1/f, self-similar)
 *   white    0                0.5  (memoryless)
 *   blue    -1                0.0  (anti-persistent)
 *   violet  -2               -0.5  (differentiated)
 *   grey     0 (perceptual)   0.5  (equal-loudness shaped)
 */

// --- deterministic PRNG (mulberry32) so the resolution is reproducible ---
function mulberry32(seed) {
  let a = seed >>> 0;
  return () => {
    a |= 0; a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// --- in-place iterative radix-2 FFT (re/im arrays, length power of 2) ---
function fft(re, im, inverse) {
  const n = re.length;
  for (let i = 1, j = 0; i < n; i++) {
    let bit = n >> 1;
    for (; j & bit; bit >>= 1) j ^= bit;
    j ^= bit;
    if (i < j) { [re[i], re[j]] = [re[j], re[i]]; [im[i], im[j]] = [im[j], im[i]]; }
  }
  for (let len = 2; len <= n; len <<= 1) {
    const ang = ((2 * Math.PI) / len) * (inverse ? 1 : -1);
    const wr = Math.cos(ang), wi = Math.sin(ang);
    for (let i = 0; i < n; i += len) {
      let cr = 1, ci = 0;
      for (let k = 0; k < len >> 1; k++) {
        const ar = re[i + k], ai = im[i + k];
        const br = re[i + k + (len >> 1)] * cr - im[i + k + (len >> 1)] * ci;
        const bi = re[i + k + (len >> 1)] * ci + im[i + k + (len >> 1)] * cr;
        re[i + k] = ar + br; im[i + k] = ai + bi;
        re[i + k + (len >> 1)] = ar - br; im[i + k + (len >> 1)] = ai - bi;
        const ncr = cr * wr - ci * wi; ci = cr * wi + ci * wr; cr = ncr;
      }
    }
  }
  if (inverse) for (let i = 0; i < n; i++) { re[i] /= n; im[i] /= n; }
}

// --- colored noise: white -> FFT -> scale bin by f^(-beta/2) -> IFFT (real) ---
function coloredNoise(N, beta, rng, perceptualGrey = false) {
  const re = new Array(N), im = new Array(N).fill(0);
  for (let i = 0; i < N; i++) re[i] = rng() * 2 - 1;
  fft(re, im, false);
  for (let k = 0; k < N; k++) {
    const f = k <= N / 2 ? k : N - k;
    let scale;
    if (perceptualGrey) {
      // grey: equal-loudness-ish mid-band emphasis (triangular around f~N/8)
      const peak = N / 8;
      scale = f === 0 ? 0 : 1 / (1 + Math.abs(Math.log((f + 1) / (peak + 1))));
    } else {
      scale = f === 0 ? 0 : Math.pow(f, -beta / 2);
    }
    re[k] *= scale; im[k] *= scale;
  }
  fft(re, im, true);
  return re.slice();
}

// --- power spectral density (positive freqs) ---
function psd(samples) {
  const N = samples.length, re = samples.slice(), im = new Array(N).fill(0);
  fft(re, im, false);
  const out = [];
  for (let k = 1; k < N / 2; k++) out.push(re[k] * re[k] + im[k] * im[k]);
  return out;
}

// --- measured spectral exponent beta via log-log least-squares (PSD ~ k^-beta) ---
function measureBeta(samples) {
  const p = psd(samples);
  let sx = 0, sy = 0, sxx = 0, sxy = 0, n = 0;
  for (let k = 0; k < p.length; k++) {
    if (p[k] <= 0) continue;
    const x = Math.log(k + 1), y = Math.log(p[k]);
    sx += x; sy += y; sxx += x * x; sxy += x * y; n++;
  }
  return -((n * sxy - sx * sy) / (n * sxx - sx * sx));
}

// --- resolution = 1 - normalized spectral entropy. 0 = pure noise, 1 = single mode ---
function resolutionOf(spectrum) {
  let tot = 0; for (const v of spectrum) tot += v;
  if (tot <= 0) return 1;
  let H = 0; for (const v of spectrum) { if (v > 0) { const q = v / tot; H -= q * Math.log(q); } }
  return 1 - H / Math.log(spectrum.length);
}

// --- the HEXON, grounded in gnosis-math/Gnosis/HexonBraid.lean +
//     SpectralNoiseEquilibrium.lean. The 6 HexonPhases = TritonPhase(past/present/
//     future = spectral MAGNITUDE 2/1/0) × BiSidedSide(lifted/contracted = slope
//     SIGN +/-). beta == signedAlpha for each NoiseColor. Array order == hexonSucc
//     (proven period 6): the braid journey spirals magnitude 2->2->1->1->0->0,
//     i.e. the weave itself flattens toward resolution. Magnitude-2 colors
//     (brown/violet) don't fit the dim-6 base plane — they ride a tower LIFT. ---
const HEXON = [
  { phase: 'pastLifted', name: 'brown', beta: 2, triton: 'past', side: 'lifted', tower: 1 },
  { phase: 'pastContracted', name: 'violet', beta: -2, triton: 'past', side: 'contracted', tower: 1 },
  { phase: 'presentLifted', name: 'pink', beta: 1, triton: 'present', side: 'lifted', tower: 0 },
  { phase: 'presentContracted', name: 'blue', beta: -1, triton: 'present', side: 'contracted', tower: 0 },
  { phase: 'futureLifted', name: 'white', beta: 0, triton: 'future', side: 'lifted', tower: 0 },
  { phase: 'futureContracted', name: 'grey', beta: 0, triton: 'future', side: 'contracted', tower: 0, grey: true },
];
// hexonSucc: advance one phase along the proven period-6 cycle (HexonBraid.lean).
const hexonSucc = (i) => (i + 1) % HEXON.length;

function main() {
  const N = 1024;
  const seed = 0x4e57; // deterministic
  const rng = mulberry32(seed);

  console.log('=== aeon-hexon-braid: noise -> absolute resolution ===\n');

  // 1) VERIFY each color is genuinely that color (measured spectral slope ~ target).
  console.log('hexon strands (target vs measured spectral exponent beta):');
  for (const c of HEXON) {
    const s = coloredNoise(N, c.beta, mulberry32(seed ^ c.name.length * 131), c.grey);
    const b = measureBeta(s);
    const H = c.grey ? '0.5*' : ((c.beta + 1) / 2).toFixed(2);
    const tag = c.grey ? 'beta=perceptual' : `beta=${c.beta >= 0 ? '+' : ''}${c.beta}`;
    console.log(`  ${c.name.padEnd(7)} ${tag.padEnd(16)} H=${H.padEnd(5)} measured=${b.toFixed(2)}`);
  }

  // 2) THE BRAID READOUT: walk hexonSucc one full period (returns after 6).
  const readout = [];
  let ph = 0; // start at pastLifted (brown)
  for (let s = 0; s <= HEXON.length; s++) { readout.push(HEXON[ph].name); ph = hexonSucc(ph); }
  console.log('\naeon hexon braid readout (hexonSucc, period 6 — returns to start):');
  console.log('  ' + readout.join(' -> '));
  console.log('  magnitudes: ' + HEXON.map((c) => Math.abs(c.beta)).concat([Math.abs(HEXON[0].beta)]).join(' '));
  console.log('  (past=mag2 brown/violet ride a tower LIFT; the weave spirals toward the flat future = resolution)');

  // 3) EVOLVE TO ABSOLUTE RESOLUTION: start at max-entropy white, then walk the
  //    hexon braid (hexonSucc) through the fractional regime, contracting each step.
  //    As the braid spirals magnitude 2->1->0, spectral entropy -> 0.
  console.log('\nevolving signal to absolute resolution along the braid (entropy -> 0):');
  let acc = psd(coloredNoise(N, 0, mulberry32(seed))); // primordial: white, max entropy
  let accTot = acc.reduce((a, b) => a + b, 0);
  acc = acc.map((v) => v / accTot);
  const gamma = 1.35; // fractional (Hurst/Wiener) contraction
  let step = 0, res = resolutionOf(acc), phase = 0, maxTower = 0, prevRes = res;
  const vitalities = [];
  console.log(`  step ${String(step).padStart(2)}  primordial(white)       knowledge=${res.toFixed(4)}  vitality=  -`);
  const RES_ABSOLUTE = 0.99;
  while (res < RES_ABSOLUTE && step < 60) {
    const color = HEXON[phase];
    maxTower = Math.max(maxTower, color.tower);
    const stepP = psd(coloredNoise(N, color.beta, mulberry32(seed + step * 2654435761), color.grey));
    let st = stepP.reduce((a, b) => a + b, 0); const sp = stepP.map((v) => v / (st || 1));
    let tot = 0; for (let i = 0; i < acc.length; i++) { acc[i] = Math.pow(acc[i], gamma) * (sp[i] + 1e-9); tot += acc[i]; }
    for (let i = 0; i < acc.length; i++) acc[i] /= tot;
    step++; res = resolutionOf(acc); phase = hexonSucc(phase);
    const vit = res - prevRes; vitalities.push(vit); prevRes = res; // vitality = delta-knowledge
    console.log(`  step ${String(step).padStart(2)}  ${color.phase.padEnd(17)} ${color.name.padEnd(6)} knowledge=${res.toFixed(4)}  vitality=Δ${vit >= 0 ? '+' : ''}${vit.toFixed(4)}`);
  }
  console.log(`  (braid climbed to tower lift ${maxTower}: soundPlaneDim ${6 + maxTower})`);

  // VERIDICAL BRIDGE to AeonVitality.lean: vitality = Δknowledge. It must rise then
  // fall to ~0 as knowledge -> omniscience (resolution 1) = heat death.
  const peak = Math.max(...vitalities), peakAt = vitalities.indexOf(peak) + 1;
  const last = vitalities[vitalities.length - 1];
  console.log('\nvitality (Δknowledge) curve — life is the gradient, not the destination:');
  console.log(`  peak vitality Δ+${peak.toFixed(4)} at step ${peakAt} (most alive mid-transit)`);
  console.log(`  final vitality Δ+${last.toFixed(4)} as knowledge -> ${res.toFixed(4)} (omniscience -> heat death)`);
  console.log(`  ${peak > last ? 'VERIDICAL ✓: vitality rose then died toward resolution — omniscience is heat death.' : 'no decay — model would be refuted'}`);

  // the resolved mode = the dominant frequency bin = the "answer" the noise resolved into
  let top = 0; for (let i = 1; i < acc.length; i++) if (acc[i] > acc[top]) top = i;
  console.log(`\nABSOLUTE RESOLUTION reached at step ${step}: resolution=${res.toFixed(4)}`);
  console.log(`  resolved single mode = bin ${top + 1}/${N / 2}  (geodesicLength:0 — one coherent carrier).`);
  console.log('  information flow: max-entropy noise -> hexon-braided fractional regime -> resolved bit.');
  return { steps: step, resolution: res, resolvedBin: top + 1 };
}

main();
